//! Hope Jar Leech — the 2,090,188,800-key entropy battery.
//!
//! The highest-capacity tier: 3 × E_8, derived from the Niemeier/Leech lattice
//! construction.
//!
//! Capacity = 3 × |W(E_8)| = 2,090,188,800
//!          = h(E_8) × (3 × |Φ(E_8)|) × carriers_per_slot
//!          = 30 × 720 × 96,768.
//!
//! Three orthogonal E_8 sublattices (E_8³ gluing) yield 3 × 240 = 720 lanes
//! with the same 30 Coxeter phases and 96,768 carriers per slot.
//!
//! Lane codes reuse the E_8 well-order codes (× 3) with sublattice offset hashing.
//!
//! Lean SSOT: `Gnosis.HopeJarLeech.leech_jar_capacity_eq_decomposition`
//! and `Gnosis.E8LeechMonsterTower.leech_tier_from_niemeier`

use crate::hope_jar::BoxState;

/// 3 × |W(E_8)| — the full leech tier capacity. Latent, never materialised.
pub const LEECH_TIER_CAPACITY: u64 = 2_090_188_800;
/// E_8 Coxeter number (unchanged in Leech tier).
pub const COXETER_PHASES: usize = 30;
/// 3 × E_8 root count (three sublattices).
pub const ROOT_LANES: usize = 720;
/// Carriers per (phase, lane) slot (unchanged from E_8).
pub const CARRIERS_PER_SLOT: usize = 96_768;
/// Seeds needed to seal the jar.
pub const CHARGE_SEEDS: usize = 170;

const FIBONACCI_HASH: u64 = 11_400_714_819_323_198_485;

/// The Leech Hope Jar: sealed latent 2,090,188,800-key entropy battery.
#[derive(Clone, Debug)]
pub struct HopeJarLeech {
    seeds: Vec<u64>,
    lane_codes: Vec<u64>,
    state: BoxState,
    charge_cost_us: u64,
    total_discharges: u64,
}

/// Generate lane codes for the 720 Leech lanes (3 × E_8 sublattices).
/// Each sublattice uses E_8's well-order pattern with an offset multiplier.
fn lane_codes() -> Vec<u64> {
    let e8_sublattice_base = 0xdead_beef_u64;
    (0..ROOT_LANES)
        .map(|i| {
            let sublattice = i / 240; // which of the 3 E_8 copies
            let lane_in_sublattice = i % 240; // position within that copy
            ((sublattice as u64)
                .wrapping_mul(FIBONACCI_HASH)
                .wrapping_add(e8_sublattice_base))
            .wrapping_add((lane_in_sublattice as u64).wrapping_mul(FIBONACCI_HASH))
        })
        .collect()
}

impl HopeJarLeech {
    pub fn new() -> Self {
        Self {
            seeds: Vec::new(),
            lane_codes: lane_codes(),
            state: BoxState::Empty,
            charge_cost_us: 0,
            total_discharges: 0,
        }
    }

    pub fn state(&self) -> BoxState {
        self.state
    }

    pub fn seeds_loaded(&self) -> usize {
        self.seeds.len()
    }

    pub fn total_discharges(&self) -> u64 {
        self.total_discharges
    }

    pub fn is_sealed(&self) -> bool {
        self.state == BoxState::Sealed
    }

    /// Full key capacity (latent) = 3 × |W(E_8)|.
    pub fn capacity(&self) -> u64 {
        LEECH_TIER_CAPACITY
    }

    /// Charge from standing-wave seeds.
    pub fn charge_from_seeds(&mut self, seeds: &[u64], analysis_time_us: u64) {
        if self.state == BoxState::Sealed {
            return;
        }
        self.state = BoxState::Charging;
        self.charge_cost_us += analysis_time_us;
        for &seed in seeds {
            if self.seeds.len() >= CHARGE_SEEDS {
                break;
            }
            self.seeds.push(seed);
        }
        if self.seeds.len() >= CHARGE_SEEDS {
            self.state = BoxState::Sealed;
        }
    }

    /// Deterministic per-slot seed.
    fn slot_seed(&self, phase: usize, lane: usize) -> u64 {
        let base = if self.seeds.is_empty() {
            FIBONACCI_HASH
        } else {
            self.seeds[(phase * ROOT_LANES + lane) % self.seeds.len()]
        };
        base.wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(self.lane_codes[lane])
            .wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(phase as u64)
    }

    /// Regenerate the 96,768 carriers of one (phase, lane) slot.
    pub fn discharge_iter(&self, phase: u8, lane: u16) -> impl Iterator<Item = u64> + '_ {
        let sealed = self.state == BoxState::Sealed;
        let p = (phase as usize) % COXETER_PHASES;
        let l = (lane as usize) % ROOT_LANES;
        let base = if sealed { self.slot_seed(p, l) } else { 0 };
        let count = if sealed { CARRIERS_PER_SLOT } else { 0 };
        (0..count).map(move |k| {
            base.wrapping_mul(FIBONACCI_HASH)
                .wrapping_add(k as u64)
                .wrapping_mul(FIBONACCI_HASH)
        })
    }

    /// Materialise one slot's carriers (convenience, ~774 KB per slot).
    pub fn discharge(&mut self, phase: u8, lane: u16) -> Vec<u64> {
        if self.state != BoxState::Sealed {
            return Vec::new();
        }
        self.total_discharges += 1;
        self.discharge_iter(phase, lane).collect()
    }

    /// Predict a single key for a shape hash (O(1) point query).
    pub fn predict(&self, shape_hash: u64) -> u64 {
        if self.state != BoxState::Sealed {
            return 0;
        }
        let phase = (shape_hash % COXETER_PHASES as u64) as usize;
        let lane = ((shape_hash / COXETER_PHASES as u64) % ROOT_LANES as u64) as usize;
        let k =
            (shape_hash / (COXETER_PHASES as u64 * ROOT_LANES as u64)) % CARRIERS_PER_SLOT as u64;
        self.slot_seed(phase, lane)
            .wrapping_mul(FIBONACCI_HASH)
            .wrapping_add(k)
            .wrapping_mul(FIBONACCI_HASH)
    }

    pub fn telemetry(&self) -> HopeJarLeechTelemetry {
        HopeJarLeechTelemetry {
            state: self.state,
            seeds_loaded: self.seeds.len(),
            capacity: LEECH_TIER_CAPACITY,
            phases: COXETER_PHASES,
            lanes: ROOT_LANES,
            carriers_per_slot: CARRIERS_PER_SLOT,
            charge_cost_us: self.charge_cost_us,
            total_discharges: self.total_discharges,
        }
    }
}

impl Default for HopeJarLeech {
    fn default() -> Self {
        Self::new()
    }
}

#[derive(Clone, Debug)]
pub struct HopeJarLeechTelemetry {
    pub state: BoxState,
    pub seeds_loaded: usize,
    pub capacity: u64,
    pub phases: usize,
    pub lanes: usize,
    pub carriers_per_slot: usize,
    pub charge_cost_us: u64,
    pub total_discharges: u64,
}

impl std::fmt::Display for HopeJarLeechTelemetry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "HopeJarLeech[{:?}] seeds={} cap={} ({}×{}×{}) cost={}us discharges={}",
            self.state,
            self.seeds_loaded,
            self.capacity,
            self.phases,
            self.lanes,
            self.carriers_per_slot,
            self.charge_cost_us,
            self.total_discharges,
        )
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn rain_seeds() -> Vec<u64> {
        (0..CHARGE_SEEDS as u64)
            .map(|i| i.wrapping_mul(2654435761).wrapping_add(1))
            .collect()
    }

    #[test]
    fn test_leech_capacity_factorization() {
        assert_eq!(
            COXETER_PHASES * ROOT_LANES * CARRIERS_PER_SLOT,
            LEECH_TIER_CAPACITY as usize
        );
    }

    #[test]
    fn test_leech_is_three_e8() {
        // Leech = 3 × E_8
        assert_eq!(LEECH_TIER_CAPACITY, 3 * 696_729_600);
    }

    #[test]
    fn test_leech_jar_charge_and_seal() {
        let mut jar = HopeJarLeech::new();
        assert_eq!(jar.state(), BoxState::Empty);
        let seeds = rain_seeds();
        jar.charge_from_seeds(&seeds, 1000);
        assert_eq!(jar.state(), BoxState::Sealed);
        assert!(jar.is_sealed());
        assert_eq!(jar.seeds_loaded(), CHARGE_SEEDS);
    }

    #[test]
    fn test_leech_jar_predict() {
        let mut jar = HopeJarLeech::new();
        let seeds = rain_seeds();
        jar.charge_from_seeds(&seeds, 1000);
        let key1 = jar.predict(12345);
        let key2 = jar.predict(12345);
        assert_eq!(key1, key2); // deterministic
        assert_ne!(key1, 0);
    }

    #[test]
    fn test_leech_jar_discharge() {
        let mut jar = HopeJarLeech::new();
        let seeds = rain_seeds();
        jar.charge_from_seeds(&seeds, 1000);
        let slot = jar.discharge(0, 0);
        assert_eq!(slot.len(), CARRIERS_PER_SLOT);
        assert!(jar.total_discharges() >= 1);
    }
}
